package github.chains;

import spoon.processing.AbstractProcessor;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtTypeReference;
import spoon.support.reflect.declaration.CtImportImpl;

import java.util.Set;

public class Main extends AbstractProcessor<CtImport> {

    @Override
    public void process(CtImport imported) {
        // Check if this is an import from the old AssertJ internal ByteBuddy package
        if (imported.getImportedType() != null && imported.getImportedType().getSimpleName().equals("ByteBuddy")) {
            CtTypeReference<?> importedType = imported.getImportedType();
            String oldPackageName = importedType.getQualifiedName().replace(".ByteBuddy", "");

            // If it's from the old AssertJ internal package, replace with external ByteBuddy
            if (oldPackageName.equals("org.assertj.core.internal.bytebuddy")) {
                // Replace with the external ByteBuddy package
                imported.setImportedType(getFactory().Type().createReference("net.bytebuddy.ByteBuddy"));
            }
        }

        // Handle all other ByteBuddy related imports from the old package
        if (imported.getImportedType() != null) {
            String qualifiedName = imported.getImportedType().getQualifiedName();

            if (qualifiedName.startsWith("org.assertj.core.internal.bytebuddy")) {
                // Replace the package name from org.assertj.core.internal.bytebuddy to net.bytebuddy
                String newQualifiedName = qualifiedName.replace("org.assertj.core.internal.bytebuddy", "net.bytebuddy");
                imported.setImportedType(getFactory().Type().createReference(newQualifiedName));
            }
        }
    }

    @Override
    public boolean isToBeProcessed(CtImport element) {
        // Process only imports from the old AssertJ internal ByteBuddy package
        if (element.getImportedType() == null) {
            return false;
        }

        String qualifiedName = element.getImportedType().getQualifiedName();
        return qualifiedName != null && qualifiedName.startsWith("org.assertj.core.internal.bytebuddy");
    }
}

