/*
 * Generic Spoon transformation to fix AssertJ Vavr compilation errors
 * 
 * Problem: assertj-vavr project uses internal AssertJ ByteBuddy classes 
 * that were removed in assertj-core 3.23.0
 * 
 * This transformation replaces:
 *   org.assertj.core.internal.bytebuddy.* -> net.bytebuddy.*
 * 
 * Usage:
 *   java -cp target/classes:$(mvn dependency:build-classpath -Dmdep.outputFile=/dev/stdout -q) github.chains.Main /path/to/project
 */

package github.chains;

import spoon.Launcher;
import spoon.processing.AbstractProcessor;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.reference.CtTypeReference;

public class Main {

    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        Launcher launcher = new Launcher();
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "-transformed");
        launcher.getEnvironment().setComplianceLevel(8);

        // Add our processor
        launcher.addProcessor(new AbstractProcessor<CtImport>() {
            @Override
            public void process(CtImport imported) {
                if (imported.getReference() != null) {
                    String importRef = imported.getReference().toString();
                    if (importRef.startsWith("org.assertj.core.internal.bytebuddy")) {
                        String newImport = importRef.replace("org.assertj.core.internal.bytebuddy", "net.bytebuddy");
                        imported.setReference(launcher.getFactory().Type().createReference(newImport));
                        System.out.println("Transformed: " + importRef + " -> " + newImport);
                    }
                }
            }

            @Override
            public boolean isToBeProcessed(CtImport element) {
                return element.getReference() != null && 
                       element.getReference().toString().startsWith("org.assertj.core.internal.bytebuddy");
            }
        });

        launcher.buildModel();
        launcher.process();
        launcher.prettyPrint();

        System.out.println("Transformation completed. Check " + sourceDirectory + "-transformed");
    }
}

